<template>
  <div>
    <h3 style="color: #888;" v-if="data.length > 0">
      当前被评人为： <h1>{{ cDetail.name }}</h1>
      设定满分为{{ totalScore }}分，当前打分为{{ sum(score) }}分{{ this.totalScore > 0 ? '，如下' : '' }}
    </h3>
    <a-card style="width: 100%; margin-bottom: 20px; border-radius: 8px;" v-for="(item, index) in data" :key="index">
      <div style="display: flex; width: 100%">
        <div style="flex: 1">
          <h2>{{ item.ruleName }}（{{ item.minScore }}-{{ item.maxScore }}分）</h2>
          <span style="white-space: pre-wrap;">{{ item.description }}</span>
          <br/>
          <div style="margin: 20px 0 0; display: flex; justify-content: center;">
            <a-button style="height: 40px; width: 40px; font-size: 30px; padding: 0" :disabled="item.minScore >= score[index]" @click="itemSubtract(index)">
              <a-icon type="minus" style="vertical-align: 0"/>
            </a-button>
            <a-input-number v-model="score[index]" style="width: 160px; margin: 0 10px; height: 40px; padding-top: 4px;" :max="item.maxScore" :min="item.minScore" @change="change1" @blur="check(index)"></a-input-number>
            <a-button style="height: 40px; width: 40px; font-size: 30px; padding: 0" :disabled="item.maxScore <= score[index]" @click="itemAdd(index)">
              <a-icon type="plus" style="vertical-align: 0"/>
            </a-button>
          </div>
          <a-slider v-if="score[index]" v-model="score[index]" :min="item.minScore" :max="item.maxScore" :step="0.01"/>
        </div>
      </div>
    </a-card>
    <a-button type="primary" v-if="data.length > 0" style="width: 100%; height: 48px; font-size: 24px;" @click="submit">
      提交
    </a-button>
  </div>
</template>
<script>
import { getScoreRuleList, getTotalScore } from '@/api/scoreRule'
import { getVoteContestantDetail } from '@/api/voteContestant'
import { submitScore } from '@/api/judge'
export default {
  data() {
    return {
      data: [],
      totalScore: 0,
      inputValue1: 100,
      score: [],
      cDetail: {},
      test1: 0,
    }
  },
  mounted() {
    this.loadData()
  },
  methods: {
    loadData() {
      getScoreRuleList(this.$route.query.voteId).then(res => {
        this.data = res.records
        if (res.records.length > 0) {
          res.records.forEach(item => {
            this.score.push(item.maxScore)
          })
        }
      })
      getVoteContestantDetail(this.$route.query.cid).then(res => {
        this.cDetail = res
      })
      getTotalScore(this.$route.query.voteId).then(res => {
        this.totalScore = res
      })
    },
    sum(arr) {
      if (arr.findIndex(item => item === '') > -1) {
        return ''
      }
      return arr.reduce((a, b) => a + b, 0).toFixed(2)
    },
    itemSubtract(index) {
      const currentScore = this.score[index]
      const minScore = this.data[index].minScore
      if (currentScore > minScore) {
        this.$set(this.score, index, currentScore - 1)
      } else {
        this.$message.warning(`分数不能低于${minScore}分`)
      }
    },
    itemAdd(index) {
      const currentScore = this.score[index]
      const maxScore = this.data[index].maxScore
      if (currentScore < maxScore) {
        this.$set(this.score, index, currentScore + 1)
      } else {
        this.$message.warning(`分数不能高于${maxScore}分`)
      }
    },
    check(e) {
      this.$set(this.score, e, this.data[e].minScore > this.score[e] ? this.data[e].minScore : this.data[e].maxScore < this.score[e] ? this.data[e].maxScore : this.score[e] === null ? this.data[e].minScore : this.score[e])
    },
    submit() {
      var result = []
      this.data.forEach((item, index) => {
        result.push({
          contestantId: this.$route.query.cid,
          ruleId: item.id,
          score: this.score[index],
          voteId: this.$route.query.voteId,
        })
      })
      submitScore(this.$route.query.voteId, result).then(res => {
        this.$message.success('评分成功')
        this.$router.go(-1)
      })
    },
    change1(e) {
      console.log(e)
    },
  },
}
</script>
<style lang="less" scoped>
::v-deep .ant-card-body {
  padding: 16px 16px 12px !important;
}
::v-deep .ant-divider-horizontal {
  margin: 12px 0;
}
::v-deep .van-dialog__header{
  padding-top: 12px;
}
::v-deep .ant-input-number-input {
  font-size: 26px;
  text-align: center;
}
</style>
